local function createMenu()\n    -- Create the main frame for the menu\n    local frame = Instance.new('Frame')\n    frame.Size = UDim2.new(0, 300, 0, 200)\n    frame.Position = UDim2.new(0.5, -150, 0.5, -100)\n    frame.BackgroundColor3 = Color3.new(1, 1, 1)\n    frame.Parent = game.Players.LocalPlayer:WaitForChild('PlayerGui')\n\n    -- Create the case name input field\n    local caseNameInput = Instance.new('TextBox')\n    caseNameInput.Size = UDim2.new(0, 200, 0, 50)\n    caseNameInput.Position = UDim2.new(0, 50, 0, 20)\n    caseNameInput.PlaceholderText = 'Enter Case Name'\n    caseNameInput.Parent = frame\n\n    -- Create start button\n    local startButton = Instance.new('TextButton')\n    startButton.Size = UDim2.new(0, 100, 0, 50)\n    startButton.Position = UDim2.new(0, 50, 0, 90)\n    startButton.Text = 'Start'\n    startButton.Parent = frame\n\n    -- Create stop button\n    local stopButton = Instance.new('TextButton')\n    stopButton.Size = UDim2.new(0, 100, 0, 50)\n    stopButton.Position = UDim2.new(0, 160, 0, 90)\n    stopButton.Text = 'Stop'\n    stopButton.Parent = frame\n\n    -- Start button click functionality\n    startButton.MouseButton1Click:Connect(function()\n        local caseName = caseNameInput.Text\n        if caseName ~= '' then\n            print('Farming NFT cases for: ' .. caseName)\n            -- Add your farming logic here\n        else\n            print('Please enter a valid case name.')\n        end\n    end)\n\n    -- Stop button click functionality\n    stopButton.MouseButton1Click:Connect(function()\n        print('Farming stopped.');\n        -- Add any cleanup logic here\n    end)\nend\n\ncreateMenu()\n